from flask import Flask, request
app = Flask(__name__)

class User:
    def __init__(self):
        self.name = ''
        self.email = ''

@app.route('/user', methods=['POST'])
def create_user():
    user = User()
    data = request.json or {}
    for key, value in data.items():  # vulnerable: attacker controls key names
        setattr(user, key, value)   # allows overwriting __class__, __dict__, etc.
    return {'status': 'created'}
